const items = $input.all();
const schedulerUrl = 'file:///C:/Users/KULLANICI_ADINIZ/linkedin-scheduler/linkedin-scheduler.html';

const postLines = items.map((item, i) => {
  const p = item.json;
  const time = p.scheduledAt ? p.scheduledAt.split('T')[1]?.slice(0,5) : '--:--';
  const preview = p.content ? p.content.slice(0, 120) + (p.content.length > 120 ? '...' : '') : '(içerik yok)';
  const media = p.mediaCount > 0 ? ` [${p.mediaCount} medya]` : '';
  const tags = p.tags ? ` #${p.tags.replace(/, /g, ' #')}` : '';
  return `${i+1}. ${time}${media}${tags}\n${preview}`;
}).join('\n\n');

const count = items.length;
const date = items[0].json.todayStr;
const firstPreview = items[0].json.content ? items[0].json.content.slice(0, 100).replace(/'/g, '').replace(/\n/g, ' ') : 'Icerik yok';
const firstMedia = items[0].json.firstMediaName || '';
const imgPath = firstMedia ? `C:\\Users\\KULLANICI_ADINIZ\\linkedin-scheduler\\${firstMedia}` : `C:\\Users\\KULLANICI_ADINIZ\\linkedin-scheduler\\logo.png`;

return [{
  json: {
    subject: `📅 LinkedIn: Bugün ${count} post paylaşılacak (${date})`,
    htmlBody: `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #0a66c2; color: white; padding: 20px; border-radius: 8px 8px 0 0;">
    <h2 style="margin:0">📅 LinkedIn Günlük Hatırlatma</h2>
    <p style="margin:8px 0 0; opacity:0.85">Bugün ${count} post paylaşılacak — ${date}</p>
  </div>
  <div style="background: #f5f5f5; padding: 20px; border-radius: 0 0 8px 8px;">
    ${items.map((item, i) => {
      const p = item.json;
      const time = p.scheduledAt ? p.scheduledAt.split('T')[1]?.slice(0,5) : '--:--';
      const preview = p.content ? p.content.slice(0,200) + (p.content.length > 200 ? '...' : '') : '(içerik yok)';
      const media = p.mediaCount > 0 ? `<span style="background:#e3f0ff;color:#0a66c2;padding:2px 8px;border-radius:12px;font-size:12px">📎 ${p.mediaCount} medya</span>` : '';
      const tags = p.tags ? p.tags.split(', ').map(t => `<span style="background:#e8f5e9;color:#2e7d32;padding:2px 8px;border-radius:12px;font-size:11px">#${t}</span>`).join(' ') : '';
      return `
        <div style="background:white;border-radius:6px;padding:16px;margin-bottom:12px;border-left:4px solid #0a66c2">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px">
            <strong style="font-size:15px">Post ${i+1}</strong>
            <span style="background:#0a66c2;color:white;padding:2px 8px;border-radius:12px;font-size:12px">⏰ ${time}</span>
            ${media}
          </div>
          <p style="color:#333;margin:8px 0;line-height:1.5">${preview.replace(/\n/g,'<br>')}</p>
          <div style="margin-top:8px">${tags}</div>
          ${p.notes ? `<div style="background:#fffbea;border:1px solid #ffd54f;border-radius:4px;padding:8px;margin-top:8px;font-size:12px;color:#666">📝 Not: ${p.notes}</div>` : ''}
        </div>`;
    }).join('')}
    <p style="color:#999;font-size:12px;text-align:center;margin-top:16px">Bu bildirim LinkedIn Scheduler tarafından gönderildi.</p>
  </div>
</div>`,
    textBody: `LinkedIn Günlük Hatırlatma - ${date}\nBugün ${count} post var:\n\n${postLines}`,
    count,
    firstPostPreview: firstPreview,
    firstMediaName: firstMedia,
    psCommand: `powershell -Command "Import-Module BurntToast; $img = if ((Test-Path '${imgPath}')) { '${imgPath}' } else { 'E:\\\\LinkedInScheduler\\\\logo.png' }; $btn = New-BTButton -Content 'Aç' -Arguments '${schedulerUrl}'; New-BurntToastNotification -Text 'LinkedIn Scheduler', '${firstPreview}' -AppLogo $img -Button $btn"`
  }
}];

const item = $input.first();
const binaryKey = Object.keys(item.binary)[0];
const rawContent = Buffer.from(item.binary[binaryKey].data, 'base64').toString('utf8');
const posts = JSON.parse(rawContent);

const today = new Date();
today.setDate(today.getDate() + 1);
const todayStr = `${today.getFullYear()}-${String(today.getMonth()+1).padStart(2,'0')}-${String(today.getDate()).padStart(2,'0')}`;

const todaysPosts = posts.filter(p => {
  if (!p.scheduledAt) return false;
  if (p.status !== 'scheduled') return false;
  const postDate = p.scheduledAt.split('T')[0];
  return postDate === todayStr;
});

if (todaysPosts.length === 0) {
  return [{ json: { hasPosts: false, count: 0, todayStr } }];
}

return todaysPosts.map(p => ({
  json: {
    hasPosts: true,
    id: p.id,
    content: p.content,
    scheduledAt: p.scheduledAt,
    tags: (p.tags || []).join(', '),
    notes: p.notes || '',
    mediaCount: (p.mediaRefs || []).length,
    todayStr
  }
}));
